#[derive(Clone, Copy, PartialEq, Eq)]
enum LineLayoutKind {
    Blank,
    Code,
    CommentOnly,
    CommaOnly,
    Verbatim,
}

struct LineLayout<'a> {
    raw: &'a str,
    trimmed: &'a str,
    analysis_trimmed: &'a str,
    has_leading_close_paren: bool,
    kind: LineLayoutKind,
    preserve_raw: bool,
    parser_depth: usize,
    auto_depth: usize,
    query_role: AutoFormatQueryRole,
    line_semantic: AutoFormatLineSemantic,
    query_base_depth: Option<usize>,
    starts_query_frame: bool,
    next_query_head_depth: Option<usize>,
    condition_header_line: Option<usize>,
    condition_role: AutoFormatConditionRole,
    final_depth: usize,
    anchor_group: Option<usize>,
    dml_case_expression_close_depth: Option<usize>,
    retain_following_non_code_scope: bool,
}

#[derive(Clone, Copy)]
enum OwnerRelativeLayoutFrameKind {
    ModelClause {
        start_parser_depth: usize,
    },
    MultilineClause {
        kind: FormatIndentedParenOwnerKind,
        nested_paren_depth: usize,
    },
}

#[derive(Clone, Copy)]
struct OwnerRelativeLayoutFrame {
    owner_depth: usize,
    kind: OwnerRelativeLayoutFrameKind,
    pending_body_header_continuation: Option<sql_text::FormatBodyHeaderContinuationState>,
}

impl OwnerRelativeLayoutFrame {
    fn model_clause(owner_depth: usize, start_parser_depth: usize) -> Self {
        Self {
            owner_depth,
            kind: OwnerRelativeLayoutFrameKind::ModelClause { start_parser_depth },
            pending_body_header_continuation: None,
        }
    }

    fn multiline_clause(kind: FormatIndentedParenOwnerKind, owner_depth: usize) -> Self {
        Self {
            owner_depth,
            kind: OwnerRelativeLayoutFrameKind::MultilineClause {
                kind,
                nested_paren_depth: 1,
            },
            pending_body_header_continuation: None,
        }
    }

    fn owner_depth(self) -> usize {
        self.owner_depth
    }

    fn owner_kind(self) -> FormatIndentedParenOwnerKind {
        match self.kind {
            OwnerRelativeLayoutFrameKind::ModelClause { .. } => {
                FormatIndentedParenOwnerKind::ModelSubclause
            }
            OwnerRelativeLayoutFrameKind::MultilineClause { kind, .. } => kind,
        }
    }

    fn body_depth(self) -> usize {
        match self.kind {
            OwnerRelativeLayoutFrameKind::ModelClause { .. } => {
                FormatIndentedParenOwnerKind::ModelSubclause.body_depth(self.owner_depth)
            }
            OwnerRelativeLayoutFrameKind::MultilineClause { kind, .. } => {
                kind.body_depth(self.owner_depth)
            }
        }
    }

    fn formatter_body_header_depth(self, text_upper: &str) -> Option<usize> {
        self.owner_kind()
            .body_header_line_state(text_upper, self.pending_body_header_continuation)
            .is_header
            .then(|| self.body_depth())
    }

    fn enforces_body_floor(self) -> bool {
        matches!(
            self.kind,
            OwnerRelativeLayoutFrameKind::MultilineClause { .. }
        )
    }

    fn note_body_header_line(&mut self, text_upper: &str) {
        self.pending_body_header_continuation = self
            .owner_kind()
            .body_header_line_state(text_upper, self.pending_body_header_continuation)
            .next_state;
    }

    fn is_match_recognize(self) -> bool {
        matches!(
            self.kind,
            OwnerRelativeLayoutFrameKind::MultilineClause {
                kind: FormatIndentedParenOwnerKind::MatchRecognize,
                ..
            }
        )
    }

    fn note_multiline_paren_event(&mut self, event: sql_text::SignificantParenEvent) {
        if let OwnerRelativeLayoutFrameKind::MultilineClause {
            nested_paren_depth, ..
        } = &mut self.kind
        {
            match event {
                sql_text::SignificantParenEvent::Open => {
                    *nested_paren_depth = nested_paren_depth.saturating_add(1);
                }
                sql_text::SignificantParenEvent::Close => {
                    *nested_paren_depth = nested_paren_depth.saturating_sub(1);
                }
            }
        }
    }

    fn is_closed_multiline_clause(self) -> bool {
        matches!(
            self.kind,
            OwnerRelativeLayoutFrameKind::MultilineClause {
                nested_paren_depth: 0,
                ..
            }
        )
    }
}

