            let is_trigger_header_body_start = trigger_header_frame.is_some()
                && !in_dml_statement
                && (crate::sql_text::starts_with_keyword_token(&trimmed_upper, "BEGIN")
                    || crate::sql_text::starts_with_keyword_token(&trimmed_upper, "DECLARE"));
