    #[test]
    fn package_body_initializer_begin_stays_at_top_level_after_case_declaration() {
        let sql = r#"CREATE OR REPLACE PACKAGE BODY fmt_pkg_extreme AS
g_last_mode VARCHAR2 (30) := 'BOOT';
FUNCTION calc_mode RETURN VARCHAR2 IS
BEGIN
  RETURN
  CASE
    WHEN 1 = 1 THEN
      'WEEKDAY_BOOT'
    ELSE
      'WEEKEND_BOOT'
  END;
END calc_mode;

BEGIN
    g_last_mode :=
    CASE
        WHEN TO_CHAR (SYSDATE, 'DY', 'NLS_DATE_LANGUAGE=ENGLISH') IN ('SAT', 'SUN') THEN
            'WEEKEND_BOOT'
        ELSE
            'WEEKDAY_BOOT'
    END;
    AUDIT ('INIT', 'package initialized. mode=' || g_last_mode);
END fmt_pkg_extreme;"#;

        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let assignment_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("g_last_mode :="))
            .expect("assignment line");
        let case_idx = lines
            .iter()
            .enumerate()
            .skip(assignment_idx + 1)
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("CASE line");

        assert!(
            formatted.contains("END calc_mode;\nBEGIN\n    g_last_mode :="),
            "package body initializer BEGIN should not remain indented under declarations, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[case_idx]),
            indent(lines[assignment_idx]).saturating_add(4),
            "initializer CASE should indent one level deeper than the := owner, got:\n{}",
            formatted
        );
        assert!(
            !formatted.contains("END calc_mode;\n\n    BEGIN\n        g_last_mode :="),
            "initializer BEGIN/body should not be shifted one extra level, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_multiline_assignment_uses_owner_frame_depth() {
        let source = r#"BEGIN
  v_txt :=
  (
    p_txt
  );
END;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let assignment_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("v_txt :="))
            .expect("assignment line");
        let open_idx = lines
            .iter()
            .enumerate()
            .skip(assignment_idx + 1)
            .find(|(_, line)| line.trim_start() == "(")
            .map(|(idx, _)| idx)
            .expect("open paren line");

        assert_eq!(
            indent(lines[open_idx]),
            indent(lines[assignment_idx]).saturating_add(4),
            "line after := should use the assignment owner depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_multiline_assignment_paren_body_tracks_open_close_depth() {
        let source = r#"BEGIN
  v_txt :=
  (
    p_txt
  );
END;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let open_idx = lines
            .iter()
            .position(|line| line.trim_start() == "(")
            .expect("open paren line");
        let body_idx = lines
            .iter()
            .enumerate()
            .skip(open_idx + 1)
            .find(|(_, line)| line.trim_start() == "p_txt")
            .map(|(idx, _)| idx)
            .expect("paren body line");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(body_idx + 1)
            .find(|(_, line)| line.trim_start() == ");" || line.trim_start() == ")")
            .map(|(idx, _)| idx)
            .expect("close paren line");

        assert_eq!(
            indent(lines[body_idx]),
            indent(lines[open_idx]).saturating_add(4),
            "body inside standalone assignment parens should be one level deeper than the open paren line, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[open_idx]),
            "close paren after standalone assignment parens should return to the open paren depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_keeps_on_duplicate_multiline_call_siblings_on_parent_frame_depth_inside_mysql_compound_body(
    ) {
        let source = r#"CREATE PROCEDURE p()
BEGIN
    INSERT INTO dept (dept_id, parent_dept_id, dept_code, dept_name, sort_no)
    VALUES (20, 10, 'SALES', 'Sales-upsert-check', 2)
    ON DUPLICATE KEY UPDATE dept_name = CONCAT(
        VALUES(dept_name),
            ' / touched'
    ),
        sort_no = VALUES(sort_no);
END;"#;

        let contexts = crate::db::QueryExecutor::auto_format_line_contexts(source);
        let multiline_string_prefix_lengths =
            SqlEditorWidget::multiline_string_continuation_prefix_lengths(
                source,
                source.lines().count(),
            );
        let mut layouts = SqlEditorWidget::build_line_layouts(
            source,
            &contexts,
            &multiline_string_prefix_lengths,
        );
        let (_, next_code_indices) = SqlEditorWidget::line_layout_code_neighbors(&layouts);
        SqlEditorWidget::resolve_code_line_layouts(&mut layouts, &next_code_indices, true);
        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let source_lines: Vec<&str> = source.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let layout_debug = |needle: &str| {
            source_lines
                .iter()
                .position(|line| line.trim_start() == needle)
                .and_then(|idx| layouts.get(idx))
                .map(|layout| {
                    format!(
                        "{needle}: parser={} auto={} final={} query_role={:?} query_base={:?} semantic={:?}",
                        layout.parser_depth,
                        layout.auto_depth,
                        layout.final_depth,
                        layout.query_role,
                        layout.query_base_depth,
                        layout.line_semantic
                    )
                })
                .unwrap_or_else(|| format!("{needle}: <missing>"))
        };
        let owner_layout = layout_debug("ON DUPLICATE KEY UPDATE dept_name = CONCAT(");
        let values_layout = layout_debug("VALUES(dept_name),");
        let literal_layout = layout_debug("' / touched'");
        let close_layout = layout_debug("),");

        let owner_idx = lines
            .iter()
            .position(|line| line.trim_start() == "ON DUPLICATE KEY UPDATE dept_name = CONCAT(")
            .expect("ON DUPLICATE owner line");
        let values_idx = lines
            .iter()
            .position(|line| line.trim_start() == "VALUES(dept_name),")
            .expect("VALUES sibling line");
        let literal_idx = lines
            .iter()
            .position(|line| line.trim_start() == "' / touched'")
            .expect("literal sibling line");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(literal_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "),")
            .map(|(idx, _)| idx)
            .expect("CONCAT close line");

        assert_eq!(
            indent(lines[values_idx]),
            indent(lines[owner_idx]).saturating_add(4),
            "first multiline CONCAT argument should stay one level below the ON DUPLICATE owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[literal_idx]),
            indent(lines[values_idx]),
            "comma sibling after VALUES() should reuse the parent frame body depth inside the compound body, got:\n{}\n{}\n{}\n{}\n{}",
            formatted,
            owner_layout,
            values_layout,
            literal_layout,
            close_layout
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[owner_idx]),
            "CONCAT close line should realign with the ON DUPLICATE owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            SqlEditorWidget::apply_parser_depth_indentation(&formatted),
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_restores_parent_call_frame_after_multiline_child_close() {
        let source = r#"SELECT
    ROUND(net_sales - IFNULL(LAG(net_sales, 1) OVER (
            PARTITION BY segment
            ORDER BY month_key
    ),
            0
    ),
        2
    ) AS mom_diff
FROM monthly;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let round_idx = lines
            .iter()
            .position(|line| {
                line.trim_start() == "ROUND(net_sales - IFNULL(LAG(net_sales, 1) OVER ("
            })
            .unwrap_or(0);
        let zero_idx = lines
            .iter()
            .enumerate()
            .skip(round_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "0")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let precision_idx = lines
            .iter()
            .enumerate()
            .skip(zero_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "2")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(precision_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == ") AS mom_diff")
            .map(|(idx, _)| idx)
            .unwrap_or(0);

        assert_eq!(
            indent(lines[zero_idx]),
            indent(lines[round_idx]).saturating_add(4),
            "pure `),` after a multiline child must restore the parent call body depth, got:\n{formatted}"
        );
        assert_eq!(
            indent(lines[precision_idx]),
            indent(lines[round_idx]).saturating_add(4),
            "outer call precision sibling should stay on the parent call body depth after the nested close, got:\n{formatted}"
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[round_idx]),
            "outer call close should realign with the parent owner depth, got:\n{formatted}"
        );
        assert_eq!(
            SqlEditorWidget::apply_parser_depth_indentation(&formatted),
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_keeps_mixed_close_expression_on_parent_call_owner_depth() {
        let source = r#"SELECT
    ROUND(SUM(
            CASE
                WHEN status <> 'CANCELLED' THEN amount
                ELSE 0
                END
            ), 2) AS total_spent,
    MAX(order_date) AS last_order_date
FROM orders;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let round_idx = lines
            .iter()
            .position(|line| line.trim_start() == "ROUND(SUM(")
            .unwrap_or(0);
        let mixed_close_idx = lines
            .iter()
            .enumerate()
            .skip(round_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "), 2) AS total_spent,")
            .map(|(idx, _)| idx)
            .unwrap_or(0);
        let sibling_idx = lines
            .iter()
            .enumerate()
            .skip(mixed_close_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "MAX(order_date) AS last_order_date")
            .map(|(idx, _)| idx)
            .unwrap_or(0);

        assert_eq!(
            indent(lines[mixed_close_idx]),
            indent(lines[round_idx]),
            "mixed close-expression line should realign with the parent call owner depth, got:\n{formatted}"
        );
        assert_eq!(
            indent(lines[sibling_idx]),
            indent(lines[round_idx]),
            "select sibling after a mixed close-expression item should return to the shared select-item owner depth, got:\n{formatted}"
        );
        assert_eq!(
            SqlEditorWidget::apply_parser_depth_indentation(&formatted),
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_multiline_operators_use_owner_frame_depth() {
        let source = r#"UPDATE qt_fmt_emp e
SET e.updated_at =
CASE
WHEN EXISTS (
SELECT 1
FROM qt_fmt_bonus b
WHERE b.emp_id = e.emp_id
AND b.amount >
(
SELECT AVG (b2.amount)
FROM qt_fmt_bonus b2
WHERE b2.bonus_year <=
2024
)
) THEN SYSTIMESTAMP
ELSE NVL (e.updated_at, SYSTIMESTAMP)
END,
e.job_title =
CASE
WHEN e.status_cd =
'ACTIVE' THEN e.job_title || ' / Core'
ELSE e.job_title
END
WHERE e.emp_id =
1;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let updated_at_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("SET e.updated_at ="))
            .expect("updated_at assignment line");
        let updated_case_idx = lines
            .iter()
            .enumerate()
            .skip(updated_at_idx + 1)
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("updated_at CASE line");
        let amount_gt_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("AND b.amount >"))
            .expect("> operator line");
        let subquery_open_idx = lines
            .iter()
            .enumerate()
            .skip(amount_gt_idx + 1)
            .find(|(_, line)| line.trim_start() == "(")
            .map(|(idx, _)| idx)
            .expect("subquery open line");
        let bonus_year_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("WHERE b2.bonus_year <="))
            .expect("<= operator line");
        let bonus_year_value_idx = lines
            .iter()
            .enumerate()
            .skip(bonus_year_idx + 1)
            .find(|(_, line)| line.trim_start() == "2024")
            .map(|(idx, _)| idx)
            .expect("<= value line");
        let job_title_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("e.job_title ="))
            .expect("job_title assignment line");
        let job_case_idx = lines
            .iter()
            .enumerate()
            .skip(job_title_idx + 1)
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("job_title CASE line");
        let status_eq_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("WHEN e.status_cd ="))
            .expect("status = line");
        let status_value_idx = lines
            .iter()
            .enumerate()
            .skip(status_eq_idx + 1)
            .find(|(_, line)| line.trim_start().starts_with("'ACTIVE' THEN"))
            .map(|(idx, _)| idx)
            .expect("status value line");
        let where_eq_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("WHERE e.emp_id ="))
            .expect("WHERE = line");
        let where_value_idx = lines
            .iter()
            .enumerate()
            .skip(where_eq_idx + 1)
            .find(|(_, line)| line.trim_start() == "1;")
            .map(|(idx, _)| idx)
            .expect("WHERE value line");

        assert_eq!(
            indent(lines[updated_case_idx]),
            indent(lines[updated_at_idx]).saturating_add(8),
            "CASE after = on the first SET item should indent relative to the semantic list-item owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[updated_case_idx]),
            indent(lines[job_case_idx]),
            "first SET item CASE should use the same semantic owner depth as later SET list items, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[subquery_open_idx]),
            indent(lines[amount_gt_idx]).saturating_add(4),
            "line after > should indent one level deeper than the operator owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[bonus_year_value_idx]),
            indent(lines[bonus_year_idx]).saturating_add(8),
            "line after <= on an inline WHERE header should indent relative to the semantic condition owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[job_case_idx]),
            indent(lines[job_title_idx]).saturating_add(4),
            "second CASE after = should indent one level deeper than its list-item owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[status_value_idx]),
            indent(lines[status_eq_idx]).saturating_add(4),
            "line after = inside CASE condition should indent one level deeper than the operator owner, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[where_value_idx]),
            indent(lines[where_eq_idx]).saturating_add(8),
            "line after = on an inline WHERE header should indent relative to the semantic condition owner, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_normalizes_parenthesized_dml_case_body_to_structural_depth() {
        let source = r#"UPDATE qt_fmt_emp e
SET e.updated_at = (
                CASE
                                WHEN e.status_cd = 'ACTIVE' THEN SYSTIMESTAMP
                                ELSE e.updated_at
                END
)
WHERE e.emp_id = 1;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let set_idx = lines
            .iter()
            .position(|line| line.trim_start() == "SET e.updated_at = (")
            .expect("should contain SET owner line");
        let case_idx = lines
            .iter()
            .enumerate()
            .skip(set_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("should contain CASE line");
        let when_idx = lines
            .iter()
            .enumerate()
            .skip(case_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start().starts_with("WHEN e.status_cd"))
            .map(|(idx, _)| idx)
            .expect("should contain WHEN line");
        let end_idx = lines
            .iter()
            .enumerate()
            .skip(when_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == "END")
            .map(|(idx, _)| idx)
            .expect("should contain END line");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(end_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == ")")
            .map(|(idx, _)| idx)
            .expect("should contain close paren line");

        assert_eq!(
            indent(lines[case_idx]),
            indent(lines[set_idx]).saturating_add(4),
            "CASE inside a parenthesized DML expression should stay exactly one structural level deeper than the owner line, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[when_idx]),
            indent(lines[case_idx]).saturating_add(4),
            "WHEN inside the parenthesized DML CASE should stay one structural level deeper than CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_idx]),
            indent(lines[case_idx]),
            "END inside the parenthesized DML CASE should realign with the CASE owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[set_idx]),
            "close paren after the DML CASE expression should return to the original owner depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_keeps_parenthesized_dml_case_close_depth_after_inline_comment_and_comment_gap(
    ) {
        let source = r#"UPDATE qt_fmt_emp e
SET e.updated_at = (
        CASE
                WHEN e.status_cd = 'ACTIVE' THEN SYSTIMESTAMP
                ELSE e.updated_at
        END -- close on next line
        -- keep pending close depth
)
WHERE e.emp_id = 1;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let set_idx = lines
            .iter()
            .position(|line| line.trim_start() == "SET e.updated_at = (")
            .expect("should contain SET owner line");
        let end_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("END -- close on next line"))
            .expect("should contain END line with inline comment");
        let comment_idx = lines
            .iter()
            .position(|line| line.trim_start() == "-- keep pending close depth")
            .expect("should contain comment-only line before close paren");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(comment_idx.saturating_add(1))
            .find(|(_, line)| line.trim_start() == ")")
            .map(|(idx, _)| idx)
            .expect("should contain close paren line");

        assert_eq!(
            indent(lines[end_idx]),
            indent(lines[set_idx]).saturating_add(4),
            "END inside the parenthesized CASE should stay aligned with CASE depth even with an inline comment, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[comment_idx]),
            indent(lines[end_idx]),
            "comment-only line between END and close paren should borrow the CASE owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[set_idx]),
            "close paren after deferred CASE close should realign with the original owner depth, got:\n{}",
            formatted
        );
    }

