    #[test]
    fn format_for_auto_formatting_normalizes_visual_odd_hanging_indent_with_tabs() {
        let source = "SELECT department_id
FROM departments d
WHERE EXISTS (
        SELECT 1
        FROM bonus_data b
        WHERE b.emp_id = d.department_id
\t      AND b.bonus_amt >= 300
    );";

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let and_idx = lines
            .iter()
            .position(|line| line.trim_start() == "AND b.bonus_amt >= 300")
            .expect("formatted output should contain EXISTS child AND");

        let where_idx = lines
            .iter()
            .position(|line| line.trim_start() == "WHERE b.emp_id = d.department_id")
            .expect("formatted output should contain EXISTS child WHERE");

        assert_eq!(
            indent(lines[and_idx]),
            indent(lines[where_idx]).saturating_add(4),
            "tab-derived odd indentation should normalize to canonical continuation depth in parser-depth layout pass, got:\n{}",
            formatted
        );
    }

    #[test]
    fn plsql_for_split_in_subquery_keeps_child_query_on_for_depth() {
        let input = r#"BEGIN
    FOR rec IN
    (
        SELECT 1
        FROM dual
    ) LOOP
        NULL;
    END LOOP;
END;"#;
        let formatted = SqlEditorWidget::format_sql_basic(input);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let for_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("FOR rec IN"))
            .expect("formatted output should contain FOR header");
        let select_idx = lines
            .iter()
            .position(|line| line.trim_start() == "SELECT 1")
            .expect("formatted output should contain child SELECT");
        let close_loop_idx = lines
            .iter()
            .position(|line| line.trim_start() == ") LOOP")
            .expect("formatted output should contain close LOOP line");
        let end_loop_idx = lines
            .iter()
            .position(|line| line.trim_start() == "END LOOP;")
            .expect("formatted output should contain END LOOP");

        assert!(
            indent(lines[select_idx]) > indent(lines[for_idx]),
            "split FOR ... IN subquery should stay nested under FOR, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_loop_idx]),
            indent(lines[for_idx]),
            "close LOOP line should return to the FOR header depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_loop_idx]),
            indent(lines[for_idx]),
            "END LOOP should stay aligned with FOR after split IN subquery, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_normalizes_overindented_end_loop_to_loop_owner_depth() {
        let source = r#"BEGIN
    LOOP
        NULL;
            END LOOP;
END;"#;
        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let loop_idx = lines
            .iter()
            .position(|line| line.trim_start() == "LOOP")
            .expect("formatted output should contain LOOP");
        let end_loop_idx = lines
            .iter()
            .position(|line| line.trim_start() == "END LOOP;")
            .expect("formatted output should contain END LOOP");
        let end_idx = lines
            .iter()
            .position(|line| line.trim_start() == "END;")
            .expect("formatted output should contain END");

        assert_eq!(
            indent(lines[end_loop_idx]),
            indent(lines[loop_idx]),
            "overindented END LOOP should realign with the LOOP owner depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_idx]),
            0,
            "outer END should remain at the enclosing BEGIN depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_normalizes_overindented_begin_body_statement_to_structural_depth(
    ) {
        let source = r#"BEGIN
                NULL;
END;"#;
        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let null_idx = lines
            .iter()
            .position(|line| line.trim_start() == "NULL;")
            .unwrap_or(0);
        let end_idx = lines
            .iter()
            .position(|line| line.trim_start() == "END;")
            .unwrap_or(0);

        assert_eq!(
            indent(lines[null_idx]),
            4,
            "BEGIN body statement should use the structural block body depth instead of preserving raw indent, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_idx]),
            0,
            "END should stay aligned with the BEGIN owner depth, got:\n{}",
            formatted
        );
    }

