    #[test]
    fn format_statement_preserves_end_for_and_end_while_suffixes() {
        let for_sql = "BEGIN\n  FOR i IN 1..3 LOOP\n    NULL;\n  END FOR;\nEND;";
        let for_formatted = SqlEditorWidget::format_sql_basic(for_sql);
        assert!(
            for_formatted.contains("END FOR;"),
            "END FOR suffix should be preserved as a single terminator line, got:\n{}",
            for_formatted
        );

        let while_sql = "BEGIN\n  WHILE i < 3 LOOP\n    i := i + 1;\n  END WHILE;\nEND;";
        let while_formatted = SqlEditorWidget::format_sql_basic(while_sql);
        assert!(
            while_formatted.contains("END WHILE;"),
            "END WHILE suffix should be preserved as a single terminator line, got:\n{}",
            while_formatted
        );
    }

    #[test]
    fn paren_case_expression_tracks_searched_case_headers() {
        let sql = r#"BEGIN
  v_val := (
    CASE v_mode
      WHEN 1 THEN 10
      ELSE 0
    END
  );
END;"#;
        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let case_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("CASE v_mode"))
            .expect("CASE line");
        let when_idx = lines
            .iter()
            .enumerate()
            .skip(case_idx + 1)
            .find(|(_, line)| line.trim_start().starts_with("WHEN 1 THEN"))
            .map(|(idx, _)| idx)
            .expect("WHEN line");
        let else_idx = lines
            .iter()
            .enumerate()
            .skip(when_idx + 1)
            .find(|(_, line)| line.trim_start() == "ELSE")
            .map(|(idx, _)| idx)
            .expect("ELSE line");
        let else_value_idx = lines
            .iter()
            .enumerate()
            .skip(else_idx + 1)
            .find(|(_, line)| line.trim_start() == "0")
            .map(|(idx, _)| idx)
            .expect("ELSE value line");
        let end_idx = lines
            .iter()
            .enumerate()
            .skip(else_value_idx + 1)
            .find(|(_, line)| line.trim_start() == "END")
            .map(|(idx, _)| idx)
            .expect("END line");

        assert!(
            formatted.contains("(\n        CASE v_mode\n            WHEN 1 THEN"),
            "CASE <expr> after '(' should get parenthesized CASE depth indent, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[else_idx]),
            indent(lines[when_idx]),
            "ELSE should align with WHEN in the parenthesized CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[else_value_idx]),
            indent(lines[else_idx]).saturating_add(4),
            "ELSE value should indent one level deeper than ELSE, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_idx]),
            indent(lines[case_idx]),
            "CASE <expr> END should keep CASE-block depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn paren_case_expression_tracks_end_case_terminator() {
        let sql = r#"BEGIN
  v_val := (
    CASE
      WHEN v_mode = 1 THEN 10
      ELSE 0
    END CASE
  );
END;"#;
        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let case_idx = lines
            .iter()
            .position(|line| line.trim_start() == "CASE")
            .expect("CASE line");
        let when_idx = lines
            .iter()
            .enumerate()
            .skip(case_idx + 1)
            .find(|(_, line)| line.trim_start().starts_with("WHEN v_mode = 1 THEN"))
            .map(|(idx, _)| idx)
            .expect("WHEN line");
        let else_idx = lines
            .iter()
            .enumerate()
            .skip(when_idx + 1)
            .find(|(_, line)| line.trim_start() == "ELSE")
            .map(|(idx, _)| idx)
            .expect("ELSE line");
        let else_value_idx = lines
            .iter()
            .enumerate()
            .skip(else_idx + 1)
            .find(|(_, line)| line.trim_start() == "0")
            .map(|(idx, _)| idx)
            .expect("ELSE value line");
        let end_case_idx = lines
            .iter()
            .enumerate()
            .skip(else_value_idx + 1)
            .find(|(_, line)| line.trim_start() == "END CASE);")
            .map(|(idx, _)| idx)
            .expect("END CASE line");

        assert!(
            formatted.contains("CASE\n            WHEN v_mode = 1 THEN"),
            "Parenthesized CASE should still format branch depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[else_idx]),
            indent(lines[when_idx]),
            "ELSE should align with WHEN in the parenthesized END CASE form, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[else_value_idx]),
            indent(lines[else_idx]).saturating_add(4),
            "ELSE value should indent one level deeper than ELSE in END CASE form, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_case_idx]),
            indent(lines[case_idx]),
            "END CASE terminator should stay aligned with CASE header in parenthesized expression, got:\n{}",
            formatted
        );
    }

    #[test]
    fn parenthesized_case_after_operator_owner_uses_paren_body_depth() {
        let sql = r#"BEGIN
    FOR i IN 1..3 LOOP
        v_sum := v_sum + (
            CASE
                WHEN MOD (i, 2) = 0 THEN
                    i * 10
                ELSE
                    i
            END
        );
    END LOOP;
END;"#;
        let formatted = SqlEditorWidget::format_sql_basic(sql);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let owner_idx = lines
            .iter()
            .position(|line| line.trim_start() == "v_sum := v_sum + (")
            .expect("owner line");
        let case_idx = lines
            .iter()
            .enumerate()
            .skip(owner_idx + 1)
            .find(|(_, line)| line.trim_start() == "CASE")
            .map(|(idx, _)| idx)
            .expect("CASE line");
        let when_idx = lines
            .iter()
            .enumerate()
            .skip(case_idx + 1)
            .find(|(_, line)| line.trim_start().starts_with("WHEN MOD (i, 2) = 0 THEN"))
            .map(|(idx, _)| idx)
            .expect("WHEN line");
        let end_idx = lines
            .iter()
            .enumerate()
            .skip(when_idx + 1)
            .find(|(_, line)| line.trim_start() == "END")
            .map(|(idx, _)| idx)
            .expect("END line");
        let close_idx = lines
            .iter()
            .enumerate()
            .skip(end_idx + 1)
            .find(|(_, line)| line.trim_start() == ");")
            .map(|(idx, _)| idx)
            .expect("close line");

        assert_eq!(
            indent(lines[case_idx]),
            indent(lines[owner_idx]).saturating_add(4),
            "CASE after an operator-owned open paren should use the paren body depth, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[when_idx]),
            indent(lines[case_idx]).saturating_add(4),
            "WHEN inside the operator-owned parenthesized CASE should stay one level deeper than CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[end_idx]),
            indent(lines[case_idx]),
            "END inside the operator-owned parenthesized CASE should stay aligned with CASE, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[owner_idx]),
            "close paren after the operator-owned CASE should return to the owner depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn starts_with_end_suffix_terminator_requires_keyword_boundary() {
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END IF;"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END /* keep */ IF;"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END LOOP"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END CASE"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END REPEAT"
        ));
        assert!(!SqlEditorWidget::starts_with_end_suffix_terminator("END"));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END FOR"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END WHILE"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END BEFORE EACH ROW"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END AFTER STATEMENT"
        ));
        assert!(SqlEditorWidget::starts_with_end_suffix_terminator(
            "END INSTEAD OF"
        ));
        assert!(!SqlEditorWidget::starts_with_end_suffix_terminator(
            "END IF_OWNER;"
        ));
        assert!(!SqlEditorWidget::starts_with_end_suffix_terminator(
            "END FORWARD;"
        ));
    }

    #[test]
    fn starts_with_plain_end_excludes_qualified_end_suffixes() {
        assert!(SqlEditorWidget::starts_with_plain_end("END"));
        assert!(SqlEditorWidget::starts_with_plain_end("END pkg;"));
        assert!(SqlEditorWidget::starts_with_plain_end(
            "END /* keep */ pkg;"
        ));
        assert!(!SqlEditorWidget::starts_with_plain_end("END FOR"));
        assert!(!SqlEditorWidget::starts_with_plain_end("END WHILE"));
        assert!(!SqlEditorWidget::starts_with_plain_end("END IF;"));
        assert!(!SqlEditorWidget::starts_with_plain_end("END LOOP"));
        assert!(!SqlEditorWidget::starts_with_plain_end("END CASE"));
        assert!(!SqlEditorWidget::starts_with_plain_end("END REPEAT"));
        assert!(!SqlEditorWidget::starts_with_plain_end(
            "END BEFORE EACH ROW"
        ));
        assert!(!SqlEditorWidget::starts_with_plain_end(
            "END AFTER STATEMENT"
        ));
        assert!(!SqlEditorWidget::starts_with_plain_end("END INSTEAD OF"));
    }

    #[test]
    fn starts_with_bare_end_matches_only_unqualified_end() {
        assert!(SqlEditorWidget::starts_with_bare_end("END"));
        assert!(SqlEditorWidget::starts_with_bare_end("END;"));
        assert!(SqlEditorWidget::starts_with_bare_end("END -- keep"));
        assert!(SqlEditorWidget::starts_with_bare_end("END /* keep */"));
        assert!(!SqlEditorWidget::starts_with_bare_end("END pkg;"));
        assert!(!SqlEditorWidget::starts_with_bare_end("END IF;"));
    }

    #[test]
    fn starts_with_mysql_custom_delimited_end_accepts_mysql_custom_delimiters() {
        let bare_end = SqlEditorWidget::tokenize_sql("END");

        assert!(SqlEditorWidget::starts_with_block_terminating_end(
            "END$$",
            &SqlEditorWidget::tokenize_sql("END$$")
        ));
        assert!(SqlEditorWidget::starts_with_block_terminating_end(
            "END//",
            &SqlEditorWidget::tokenize_sql("END//")
        ));
        assert!(!SqlEditorWidget::starts_with_block_terminating_end(
            "END)",
            &SqlEditorWidget::tokenize_sql("END)")
        ));
        assert!(SqlEditorWidget::starts_with_block_terminating_end(
            "END", &bare_end
        ));
    }

    #[test]
