    #[test]
    fn apply_parser_depth_indentation_keeps_window_order_by_under_over_paren_after_comment() {
        let source = r#"SELECT o.order_id,
    x.max_price,
    -- [AU] 분위수 계산
    NTILE (4) OVER (
/* AV: 금액 기준 분위 */
ORDER BY x.total_amt DESC NULLS LAST) AS amt_quartile
FROM recent_orders o;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let ntile_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("NTILE (4) OVER ("))
            .unwrap_or(0);
        let comment_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("/* AV: 금액 기준 분위 */"))
            .unwrap_or(0);
        let order_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("ORDER BY x.total_amt"))
            .unwrap_or(0);

        assert!(
            indent(lines[comment_idx]) > indent(lines[ntile_idx]),
            "window comment line should stay nested under OVER (, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[comment_idx]),
            indent(lines[order_idx]),
            "comment and ORDER BY inside OVER (...) should share the same continuation depth, got:\n{}",
            formatted
        );
    }

    #[test]
    fn apply_parser_depth_indentation_keeps_outer_analytic_over_depth_after_nested_over() {
        let source = r#"SELECT
    SUM (sal) OVER (
        PARTITION BY deptno
        ORDER BY (
            SELECT MAX (inner_val) OVER (
                PARTITION BY grp
                ORDER BY inner_val
            )
            FROM dual
        )
        ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
    ) AS running_sal
FROM emp;"#;

        let formatted = SqlEditorWidget::apply_parser_depth_indentation(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let indent = |line: &str| line.len().saturating_sub(line.trim_start().len());

        let over_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("SUM (sal) OVER ("))
            .unwrap_or(0);
        let outer_partition_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("PARTITION BY deptno"))
            .unwrap_or(0);
        let inner_partition_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with("PARTITION BY grp"))
            .unwrap_or(0);
        let rows_idx = lines
            .iter()
            .position(|line| {
                line.trim_start()
                    .starts_with("ROWS BETWEEN UNBOUNDED PRECEDING")
            })
            .unwrap_or(0);
        let close_idx = lines
            .iter()
            .position(|line| line.trim_start().starts_with(") AS running_sal"))
            .unwrap_or(0);

        assert_eq!(
            indent(lines[outer_partition_idx]),
            indent(lines[over_idx]).saturating_add(4),
            "outer OVER subclauses should stay one level deeper than the OVER owner line, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[rows_idx]),
            indent(lines[outer_partition_idx]),
            "ROWS BETWEEN should return to the outer OVER subclause depth after nested OVER closes, got:\n{}",
            formatted
        );
        assert!(
            indent(lines[inner_partition_idx]) > indent(lines[outer_partition_idx]),
            "nested OVER subclauses should stay deeper than the outer OVER subclauses, got:\n{}",
            formatted
        );
        assert_eq!(
            indent(lines[close_idx]),
            indent(lines[over_idx]),
            "analytic OVER close should realign with the OVER owner line, got:\n{}",
            formatted
        );
    }

