    #[test]
    fn format_for_auto_formatting_keeps_from_aligned_before_unpivot_after_multiline_select_list() {
        let source = r#"CREATE OR REPLACE PROCEDURE test_open_with_proc IS
    p_rc SYS_REFCURSOR;
BEGIN
    OPEN p_rc FOR
        WITH src AS (
            SELECT deptno,
                job,
                sal
            FROM emp
        ),
        pivoted AS (
            SELECT *
            FROM src PIVOT (
                SUM (sal) AS sum_sal FOR
                deptno IN (
                    10 AS D10, 20 AS D20, 30 AS D30)
            )
        )
        SELECT job,
            dept_tag,
            sal_amt
        FROM pivoted UNPIVOT (
            sal_amt
            FOR dept_tag IN (
                D10 AS '10', D20 AS '20', D30 AS '30')
        )
        WHERE sal_amt IS NOT NULL
        ORDER BY job,
            dept_tag;
END;"#;

        let formatted = SqlEditorWidget::format_for_auto_formatting(source, false);

        assert!(
            formatted.contains(
                "        SELECT job,\n            dept_tag,\n            sal_amt\n        FROM pivoted\n        UNPIVOT ("
            ),
            "FROM before UNPIVOT should realign to the SELECT base depth and UNPIVOT should start on its own line, got:\n{}",
            formatted
        );
        assert!(
            !formatted.contains(
                "        SELECT job,\n            dept_tag,\n            sal_amt\n            FROM pivoted"
            ),
            "FROM before UNPIVOT must not remain indented like a select-list continuation, got:\n{}",
            formatted
        );
    }

