    // Bug candidate 3: MERGE branch alignment
    #[test]
    fn format_sql_basic_merge_using_and_when_branches_alignment() {
        let source = "MERGE INTO tgt t USING src s ON (t.id = s.id) WHEN MATCHED THEN UPDATE SET t.val = s.val, t.updated_at = SYSTIMESTAMP WHEN NOT MATCHED THEN INSERT (id, val, updated_at) VALUES (s.id, s.val, SYSTIMESTAMP);";
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let leading = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let find_line = |prefix: &str| -> Option<&str> {
            lines
                .iter()
                .copied()
                .find(|l| l.trim_start().starts_with(prefix))
        };

        // USING should be present and at base depth (same as MERGE)
        let merge_line = find_line("MERGE INTO").unwrap_or("");
        let using_line = find_line("USING");
        let on_line = find_line("ON (").unwrap_or("");
        assert!(
            !merge_line.is_empty() && using_line.is_some() && !on_line.is_empty(),
            "MERGE/USING/ON lines should all be present, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(using_line.unwrap_or("")),
            leading(merge_line),
            "USING should stay on the MERGE base depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(on_line),
            leading(merge_line).saturating_add(4),
            "ON should stay one level deeper than the MERGE base depth, got:\n{}",
            formatted
        );

        // Both WHEN branches at same depth
        let when_matched = find_line("WHEN MATCHED THEN").unwrap_or("");
        let when_not_matched = find_line("WHEN NOT MATCHED THEN").unwrap_or("");
        assert!(
            !when_matched.is_empty() && !when_not_matched.is_empty(),
            "Both WHEN branches should be present, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(when_matched),
            leading(when_not_matched),
            "WHEN MATCHED and WHEN NOT MATCHED should be at same depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(when_matched),
            leading(merge_line),
            "WHEN branches should return to the MERGE base depth after ON, got:\n{}",
            formatted
        );

        // UPDATE SET and INSERT should be indented under their WHEN
        let update_line = find_line("UPDATE SET");
        let insert_line = find_line("INSERT (");
        assert!(
            update_line.is_some() && insert_line.is_some(),
            "UPDATE SET and INSERT should be present, got:\n{}",
            formatted
        );
        assert!(
            leading(update_line.unwrap()) > leading(when_matched),
            "UPDATE SET should be deeper than WHEN MATCHED, got:\n{}",
            formatted
        );

        // Idempotence
        let formatted_again = SqlEditorWidget::format_sql_basic(&formatted);
        assert_eq!(
            formatted, formatted_again,
            "MERGE formatting should be idempotent.\nFirst:\n{}\nSecond:\n{}",
            formatted, formatted_again
        );
    }

    #[test]
    fn format_sql_basic_merge_update_set_continuation_uses_branch_body_depth() {
        let source = r#"MERGE INTO qt_fmt_emp t
USING (
        WITH recent_sales AS (
            SELECT
                s.emp_id,
                SUM ((s.qty * s.unit_price) - s.discount_amt + s.tax_amt) AS recent_amt
            FROM qt_fmt_sales s
            WHERE s.sale_date >= DATE '2024-03-01'
            GROUP BY s.emp_id
        ),
    scored AS (
            SELECT
                e.emp_id,
                e.note_text,
                rs.recent_amt,
                CASE
                    WHEN NVL (rs.recent_amt, 0) >= 50000 THEN ' | HOT'
                    WHEN NVL (rs.recent_amt, 0) >= 20000 THEN ' | WARM'
                    ELSE ' | COLD'
                END AS score_tag
            FROM qt_fmt_emp e
            LEFT JOIN recent_sales rs
                ON rs.emp_id = e.emp_id
            WHERE e.dept_id = 30
        )
        SELECT
            s.emp_id,
            SUBSTR (NVL (s.note_text, 'sales-profile') || s.score_tag || ' | recent=' || TO_CHAR (NVL (s.recent_amt, 0)), 1, 4000) AS new_note_text
        FROM scored s
    ) src
    ON (t.emp_id = src.emp_id)
WHEN MATCHED THEN
    UPDATE SET t.note_text = src.new_note_text,
        t.updated_at = SYSTIMESTAMP;"#;
        let formatted = SqlEditorWidget::format_sql_basic(source);
        let lines: Vec<&str> = formatted.lines().collect();
        let leading = |line: &str| line.len().saturating_sub(line.trim_start().len());
        let find_line = |prefix: &str| -> Option<&str> {
            lines
                .iter()
                .copied()
                .find(|line| line.trim_start().starts_with(prefix))
        };

        let when_matched = find_line("WHEN MATCHED THEN").unwrap_or("");
        let update_line = find_line("UPDATE SET t.note_text = src.new_note_text,").unwrap_or("");
        let updated_at_line = find_line("t.updated_at = SYSTIMESTAMP;").unwrap_or("");
        let with_line = find_line("WITH recent_sales AS (").unwrap_or("");
        let scored_line = find_line("scored AS (").unwrap_or("");

        assert!(
            !when_matched.is_empty()
                && !update_line.is_empty()
                && !updated_at_line.is_empty()
                && !with_line.is_empty()
                && !scored_line.is_empty(),
            "expected MERGE branch lines to be present, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(scored_line),
            leading(with_line),
            "nested USING CTE siblings should align on the same WITH base depth, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(update_line),
            leading(when_matched).saturating_add(4),
            "UPDATE SET should stay one structural level deeper than WHEN MATCHED, got:\n{}",
            formatted
        );
        assert_eq!(
            leading(updated_at_line),
            leading(update_line).saturating_add(4),
            "MERGE UPDATE SET continuation should use the branch body list depth, got:\n{}",
            formatted
        );
    }

